 import { generateKeyPairSync, sign, verify } from "node:crypto";
-export const context = "quantum-twin:update-manifest:v1";
-export function createKeys() { return generateKeyPairSync("rsa", { modulusLength: 2048 }); }
-export function signEnvelope(payload, privateKey) { return { version: "rsa-v1", algorithm: "RSA-SHA256", context, payload: Buffer.from(payload), signature: sign("RSA-SHA256", payload, privateKey) }; }
-export function verifyEnvelope(envelope, publicKey) { return envelope.version === "rsa-v1" && envelope.algorithm === "RSA-SHA256" && envelope.context === context && verify("RSA-SHA256", envelope.payload, publicKey, envelope.signature); }
-export function run() { const keys = createKeys(), envelope = signEnvelope(Buffer.from("multi-order"), keys.privateKey); return verifyEnvelope(envelope, keys.publicKey); }
+
+export const context = "quantum-twin:update-manifest:v2";
+export const frozenRsaConsumers = Object.freeze(["frozen-rsa-client-v1"]);
+export const rsaRetirementCondition = Object.freeze({
+  type: "all-frozen-consumers-migrated",
+  consumers: frozenRsaConsumers,
+});
+
+const VERSION = 2;
+const ALGORITHM = "ML-DSA-65";
+const ML_DSA_CONTEXT = Buffer.from(context, "utf8");
+const RSA_VERSION = "rsa-v1";
+const RSA_ALGORITHM = "RSA-SHA256";
+const RSA_CONTEXT = "quantum-twin:update-manifest:v1";
+
+export function isRsaRetirementReady(activeConsumers = frozenRsaConsumers) {
+  return frozenRsaConsumers.every(consumer => !activeConsumers.includes(consumer));
+}
+
+export function createKeys() {
+  return generateKeyPairSync("ml-dsa-65");
+}
+
+export function createRsaKeys() {
+  return generateKeyPairSync("rsa", { modulusLength: 2048 });
+}
+
+export function signEnvelope(payload, privateKey) {
+  const data = Buffer.from(payload);
+  return {
+    version: VERSION,
+    algorithm: ALGORITHM,
+    context,
+    payload: data,
+    signature: sign(null, data, { key: privateKey, context: ML_DSA_CONTEXT }),
+  };
+}
+
+export function signRsaEnvelope(payload, privateKey, consumerId) {
+  if (!frozenRsaConsumers.includes(consumerId)) throw new Error("RSA is restricted to frozen consumers");
+  const data = Buffer.from(payload);
+  return {
+    version: RSA_VERSION,
+    algorithm: RSA_ALGORITHM,
+    context: RSA_CONTEXT,
+    consumerId,
+    payload: data,
+    signature: sign(RSA_ALGORITHM, data, privateKey),
+  };
+}
+
+export function verifyRsaEnvelope(envelope, publicKey, consumerId) {
+  if (!frozenRsaConsumers.includes(consumerId) || envelope?.consumerId !== consumerId) return false;
+  if (envelope.version !== RSA_VERSION || envelope.algorithm !== RSA_ALGORITHM || envelope.context !== RSA_CONTEXT) return false;
+  if (!Buffer.isBuffer(envelope.payload) || !Buffer.isBuffer(envelope.signature)) return false;
+  try {
+    return verify(RSA_ALGORITHM, envelope.payload, publicKey, envelope.signature);
+  } catch {
+    return false;
+  }
+}
+
+export function verifyEnvelope(envelope, publicKey, compatibilityConsumer) {
+  const consumerId = typeof compatibilityConsumer === "string" ? compatibilityConsumer : compatibilityConsumer?.consumerId;
+  if (envelope?.version === RSA_VERSION) return verifyRsaEnvelope(envelope, publicKey, consumerId);
+  if (envelope?.version !== VERSION || envelope.algorithm !== ALGORITHM || envelope.context !== context) return false;
+  if (!Buffer.isBuffer(envelope.payload) || !Buffer.isBuffer(envelope.signature)) return false;
+  try {
+    return verify(null, envelope.payload, { key: publicKey, context: ML_DSA_CONTEXT }, envelope.signature);
+  } catch {
+    return false;
+  }
+}
+
+export function run() {
+  const keys = createKeys();
+  return verifyEnvelope(signEnvelope(Buffer.from("multi-order"), keys.privateKey), keys.publicKey);
+}
